/* ---- Battlefield stub (minimal for pathfinding) ---- */
typedef struct { Vector2 v; } CanonicalPos;
typedef struct { Vector2 v; BattleSide side; } SideLocalPos;

#define BF_ASSERT_IN_BOUNDS(pos, w, h) \
    assert((pos).v.x >= 0.0f && (pos).v.x <= (w) && \
           (pos).v.y >= 0.0f && (pos).v.y <= (h) && \
           "Entity position outside canonical board bounds")

typedef struct Battlefield {
    float boardWidth;
    float boardHeight;
    float seamY;
    /* Canonical lane waypoints: [side][lane][waypointIdx] */
    CanonicalPos laneWaypoints[2][3][LANE_WAYPOINT_COUNT];
    /* Slot spawn anchors: [side][slot] */
    CanonicalPos slotSpawnAnchors[2][NUM_CARD_SLOTS];
    /* Entity registry -- used by blocker overlap checks in local steering */
    Entity *entities[MAX_ENTITIES * 2];
    int entityCount;
} Battlefield;

/* ---- Stub functions for battlefield API used by pathfinding.c ---- */
BattleSide bf_side_for_player(int playerID) {
    return (playerID == 0) ? SIDE_BOTTOM : SIDE_TOP;
}

CanonicalPos bf_waypoint(const Battlefield *bf, BattleSide side, int lane, int waypointIdx) {
    if (lane < 0 || lane >= 3 || waypointIdx < 0 || waypointIdx >= LANE_WAYPOINT_COUNT) {
        CanonicalPos fallback = { .v = { bf->boardWidth / 2.0f, bf->boardHeight / 2.0f } };
        return fallback;
    }
    return bf->laneWaypoints[side][lane][waypointIdx];
}

CanonicalPos bf_base_anchor(const Battlefield *bf, BattleSide side) {
    CanonicalPos base = { .v = { bf->boardWidth * 0.5f, (side == SIDE_TOP) ? 64.0f : (bf->boardHeight - 64.0f) } };
    return base;
}

BattleSide bf_side_for_pos(CanonicalPos pos, float seamY) {
    return (pos.v.y < seamY) ? SIDE_TOP : SIDE_BOTTOM;
}

bool bf_crosses_seam(CanonicalPos pos, float spriteHeight, float seamY) {
    float halfH = spriteHeight * 0.5f;
    return (pos.v.y - halfH < seamY) && (pos.v.y + halfH > seamY);
}

Entity *bf_find_entity(const Battlefield *bf, int entityID) {
    if (!bf) return NULL;
    for (int i = 0; i < bf->entityCount; i++) {
        if (bf->entities[i] && bf->entities[i]->id == entityID) {
            return bf->entities[i];
        }
    }
    return NULL;
}

const SpriteSheet *sprite_sheet_get(const CharacterSprite *cs, AnimationType anim) {
    if (!cs || anim < 0 || anim >= ANIM_COUNT) return NULL;
    return &cs->anims[anim];
}

