/* ---- Existing-test compatibility shims ----
 *
 * The legacy 45 tests were written against the pre-Phase-3b candidate-fan
 * stepper and encode hard-ally-blocking behavior (e.g. "blocked on
 * waypoint, do not advance") that Rev 3 of the plan explicitly retires.
 * Rather than rewrite every legacy test in one commit, these macros
 * inject a NULL NavFrame at the legacy call sites. When nav is NULL,
 * pathfind_step_entity falls through to pathfind_try_step_toward, which
 * preserves the old behavior. New Phase 3b tests live at the bottom of
 * this file and bypass the macros via the parenthesized-name trick to
 * call the real function with a real nav snapshot. */
#define pathfind_step_entity(e, bf, dt) \
    pathfind_step_entity((e), (NavFrame *)0, (bf), (dt))
#define pathfind_move_toward_goal(e, goal, r, bf, dt) \
    pathfind_move_toward_goal((e), (goal), (r), (NavFrame *)0, (bf), (dt))

/* ---- Test helpers ---- */

static bool approx_eq(float a, float b, float eps) {
    return fabsf(a - b) < eps;
}

/* Build a Battlefield stub with manually generated straight-line waypoints for
 * both sides. This provides predictable positions for testing pathfinding
 * behavior without depending on bf_init's full logic. */
static Battlefield make_test_battlefield(void) {
    Battlefield bf;
    memset(&bf, 0, sizeof(Battlefield));
    bf.boardWidth = BOARD_WIDTH;
    bf.boardHeight = BOARD_HEIGHT;
    bf.seamY = SEAM_Y;

    float laneWidth = (float)BOARD_WIDTH / 3.0f;
    float bottomSpawnY = 960.0f + 960.0f * 0.8f; /* 1728 */
    float bottomEndY = 192.0f;
    float topSpawnY = 192.0f;
    float topEndY = 960.0f + 960.0f * 0.8f; /* 1728 */

    for (int lane = 0; lane < 3; lane++) {
        float centerX = (lane + 0.5f) * laneWidth;
        for (int wp = 0; wp < LANE_WAYPOINT_COUNT; wp++) {
            float t = (float)wp / (float)(LANE_WAYPOINT_COUNT - 1);
            float bottomY = bottomSpawnY + (bottomEndY - bottomSpawnY) * t;
            float topY = topSpawnY + (topEndY - topSpawnY) * t;
            bf.laneWaypoints[SIDE_BOTTOM][lane][wp].v = (Vector2){ centerX, bottomY };
            bf.laneWaypoints[SIDE_TOP][lane][wp].v = (Vector2){ centerX, topY };
        }
        bf.slotSpawnAnchors[SIDE_BOTTOM][lane] = bf.laneWaypoints[SIDE_BOTTOM][lane][0];
        bf.slotSpawnAnchors[SIDE_TOP][lane] = bf.laneWaypoints[SIDE_TOP][lane][0];
    }

    return bf;
}

