/* Register a blocker entity with the minimal battlefield stub. Caller owns
 * the storage; this helper just pushes a pointer into the registry. */
static void bf_test_register(Battlefield *bf, Entity *e) {
    bf->entities[bf->entityCount++] = e;
}

static bool test_spawn_pos_overlaps(const Battlefield *bf, Vector2 pos,
                                    float bodyRadius) {
    if (!bf) return false;

    for (int i = 0; i < bf->entityCount; i++) {
        const Entity *other = bf->entities[i];
        if (!other || !other->alive || other->markedForRemoval) continue;
        if (other->type == ENTITY_PROJECTILE) continue;

        float dx = other->position.x - pos.x;
        float dy = other->position.y - pos.y;
        float minDist = bodyRadius + other->bodyRadius + PATHFIND_CONTACT_GAP;
        if (dx * dx + dy * dy < minDist * minDist) return true;
    }

    return false;
}

static bool test_spawn_pos_in_bounds(const Battlefield *bf, Vector2 pos,
                                     float bodyRadius) {
    if (!bf) return false;

    return pos.x - bodyRadius >= 0.0f &&
           pos.x + bodyRadius <= bf->boardWidth &&
           pos.y - bodyRadius >= 0.0f &&
           pos.y + bodyRadius <= bf->boardHeight;
}

static bool test_find_spawn_anchor(const Battlefield *bf, BattleSide side,
                                   int slotIndex, float bodyRadius,
                                   Vector2 *outPos) {
    if (!bf || !outPos || bodyRadius <= 0.0f ||
        slotIndex < 0 || slotIndex >= NUM_CARD_SLOTS) {
        return false;
    }

    static const float lateralMults[] = {
        0.0f, -1.25f, 1.25f, -2.5f, 2.5f, -3.75f, 3.75f, -5.0f, 5.0f
    };
    int lateralCount = (int)(sizeof(lateralMults) / sizeof(lateralMults[0]));
    Vector2 anchor = bf->slotSpawnAnchors[side][slotIndex].v;
    float behindSign = (side == SIDE_BOTTOM) ? 1.0f : -1.0f;

    for (int row = 0; row < 4; row++) {
        float yOffset = behindSign * bodyRadius * (float)row;
        for (int i = 0; i < lateralCount; i++) {
            Vector2 candidate = {
                anchor.x + lateralMults[i] * bodyRadius,
                anchor.y + yOffset
            };
            if (!test_spawn_pos_in_bounds(bf, candidate, bodyRadius)) continue;
            if (test_spawn_pos_overlaps(bf, candidate, bodyRadius)) continue;
            *outPos = candidate;
            return true;
        }
    }

    return false;
}

static void test_step_pack(Entity *pack, int count, Battlefield *bf, int ticks) {
    for (int tick = 0; tick < ticks; tick++) {
        for (int i = 0; i < count; i++) {
            pathfind_step_entity(&pack[i], bf, 1.0f / 60.0f);
        }
    }
}

static int test_spawn_same_lane_pack(Battlefield *bf, Entity *pack, int targetCount,
                                     BattleSide side, int slotIndex, int lane,
                                     int maxTicks) {
    if (!bf || !pack || targetCount <= 0 || maxTicks <= 0) return 0;

    int spawned = 0;
    for (int tick = 0; tick < maxTicks && spawned < targetCount; tick++) {
        Vector2 spawnPos;
        if (test_find_spawn_anchor(bf, side, slotIndex, 14.0f, &spawnPos)) {
            pack[spawned] = make_test_entity(lane, 1, 58.0f);
            pack[spawned].ownerID = (side == SIDE_BOTTOM) ? 0 : 1;
            pack[spawned].position = spawnPos;
            bf_test_register(bf, &pack[spawned]);
            spawned++;
        }

        test_step_pack(pack, spawned, bf, 1);
    }

    return spawned;
}

static float test_pack_total_y(const Entity *pack, int count) {
    float totalY = 0.0f;
    for (int i = 0; i < count; i++) {
        totalY += pack[i].position.y;
    }
    return totalY;
}

static int test_pack_units_at_or_past_waypoint(const Entity *pack, int count,
                                               int waypointIndex) {
    int units = 0;
    for (int i = 0; i < count; i++) {
        if (pack[i].waypointIndex >= waypointIndex) units++;
    }
    return units;
}

/* ---- CORE-01: Canonical waypoints progress toward enemy ---- */
static void test_canonical_waypoints_progress(void) {
    Battlefield bf = make_test_battlefield();

    for (int lane = 0; lane < 3; lane++) {
        /* Waypoints progress toward enemy (Y decreases for SIDE_BOTTOM) */
        for (int i = 1; i < LANE_WAYPOINT_COUNT; i++) {
            assert(bf.laneWaypoints[SIDE_BOTTOM][lane][i].v.y <
                   bf.laneWaypoints[SIDE_BOTTOM][lane][i - 1].v.y);
        }
    }
}

/* ---- CORE-01b: Center lane has consistent lateral position ---- */
static void test_center_lane_consistent_x(void) {
    Battlefield bf = make_test_battlefield();

    float centerX = bf.laneWaypoints[SIDE_BOTTOM][1][0].v.x;
    for (int i = 1; i < LANE_WAYPOINT_COUNT; i++) {
        assert(approx_eq(bf.laneWaypoints[SIDE_BOTTOM][1][i].v.x, centerX, 0.1f));
    }
}

/* ---- CORE-01d: Movement stepping advances waypointIndex ---- */
static void test_movement_step_advances_waypoint(void) {
    Battlefield bf = make_test_battlefield();

    /* Entity starts at waypoint[1] position -- large dt to guarantee overshoot */
    Entity e = make_test_entity(1, 1, 50000.0f);
    e.position = bf.laneWaypoints[SIDE_BOTTOM][1][1].v;

    bool walking = pathfind_step_entity(&e, &bf, 1.0f);
    (void)walking;
    /* Should have advanced past waypoint 1 */
    assert(e.waypointIndex >= 2);

    /* Normal speed: entity moves toward target but doesn't overshoot */
    Entity e2 = make_test_entity(1, 1, 10.0f); /* slow speed */
    e2.position = bf.laneWaypoints[SIDE_BOTTOM][1][1].v;
    /* Move slightly off the waypoint so there's distance to cover */
    e2.position.y += 50.0f;

    int prevIdx = e2.waypointIndex;
    pathfind_step_entity(&e2, &bf, 1.0f / 60.0f);
    /* With slow speed and 50px distance, should still be on same waypoint */
    assert(e2.waypointIndex == prevIdx);
}

/* ---- CORE-01e: Idle at last waypoint ---- */
static void test_idle_at_last_waypoint(void) {
    Battlefield bf = make_test_battlefield();

    /* Place entity near the last segment and step until the continuous lane
     * cursor reaches the lane end. */
    Entity e = make_test_entity(1, LANE_WAYPOINT_COUNT - 1, 50000.0f);
    e.position = bf.laneWaypoints[SIDE_BOTTOM][1][LANE_WAYPOINT_COUNT - 2].v;

    bool walking = true;
    for (int i = 0; i < 8 && walking; i++) {
        walking = pathfind_step_entity(&e, &bf, 1.0f / 60.0f);
    }

    /* Should have reached end and transitioned to idle */
    assert(walking == false);
    assert(e.state == ESTATE_IDLE);
    assert(e.waypointIndex >= LANE_WAYPOINT_COUNT);
}

/* ---- CORE-01f: Sprite direction from movement vector ---- */
static void test_sprite_direction(void) {
    AnimState anim;
    memset(&anim, 0, sizeof(AnimState));

    /* Moving left -> DIR_SIDE, flipH=true */
    anim.dir = DIR_UP;
    pathfind_apply_direction(&anim, (Vector2){-100, -10});
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);

    /* Moving right -> DIR_SIDE, flipH=false */
    pathfind_apply_direction(&anim, (Vector2){100, -10});
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    /* Pure vertical movement keeps the right-facing bias */
    pathfind_apply_direction(&anim, (Vector2){0, -100});
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    /* Same right-facing bias when moving down */
    pathfind_apply_direction(&anim, (Vector2){0, 100});
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    /* Zero vector: direction unchanged */
    anim.dir = DIR_UP;
    anim.flipH = false;
    pathfind_apply_direction(&anim, (Vector2){0, 0});
    assert(anim.dir == DIR_UP);

    /* Any nonzero X produces DIR_SIDE */
    memset(&anim, 0, sizeof(AnimState));
    pathfind_apply_direction(&anim, (Vector2){-1, -100});
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);
}

/* ---- CORE-01g: Perspective-aware vertical direction by owner side ---- */
static void test_sprite_direction_for_side(void) {
    AnimState anim;
    memset(&anim, 0, sizeof(AnimState));

    pathfind_apply_direction_for_side(&anim, (Vector2){100, 0}, SIDE_BOTTOM);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    pathfind_apply_direction_for_side(&anim, (Vector2){-100, 0}, SIDE_BOTTOM);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);

    pathfind_apply_direction_for_side(&anim, (Vector2){0, -100}, SIDE_BOTTOM);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    pathfind_apply_direction_for_side(&anim, (Vector2){0, 100}, SIDE_BOTTOM);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);

    // Top-side sprites still invert flipH so the 180-degree presentation
    // rotation preserves a right-facing bias.
    pathfind_apply_direction_for_side(&anim, (Vector2){0, 100}, SIDE_TOP);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);

    pathfind_apply_direction_for_side(&anim, (Vector2){0, -100}, SIDE_TOP);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);

    pathfind_apply_direction_for_side(&anim, (Vector2){100, 0}, SIDE_TOP);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == true);

    pathfind_apply_direction_for_side(&anim, (Vector2){-100, 0}, SIDE_TOP);
    assert(anim.dir == DIR_SIDE);
    assert(anim.flipH == false);
}

/* ---- CORE-01ga: Presentation swaps once the entity crosses the seam ---- */
static void test_presentation_side_for_position(void) {
    assert(pathfind_presentation_side_for_position((Vector2){540.0f, 959.0f}, SEAM_Y) == SIDE_TOP);
    assert(pathfind_presentation_side_for_position((Vector2){540.0f, 960.0f}, SEAM_Y) == SIDE_BOTTOM);
    assert(pathfind_presentation_side_for_position((Vector2){540.0f, 1200.0f}, SEAM_Y) == SIDE_BOTTOM);
}

/* ---- CORE-01h: All top-side sprites rotate 180 degrees ---- */
static void test_sprite_rotation_for_side(void) {
    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_SIDE, SIDE_BOTTOM), 0.0f, 0.001f));
    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_UP, SIDE_BOTTOM), 0.0f, 0.001f));
    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_DOWN, SIDE_BOTTOM), 0.0f, 0.001f));

    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_SIDE, SIDE_TOP), 180.0f, 0.001f));
    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_UP, SIDE_TOP), 180.0f, 0.001f));
    assert(approx_eq(pathfind_sprite_rotation_for_side(DIR_DOWN, SIDE_TOP), 180.0f, 0.001f));
}

static void test_crossed_over_combat_troop_uses_owner_side_horizontal_facing(void) {
    Battlefield bf = make_test_battlefield();

    Entity bottomInvader = make_test_entity(1, 4, 0.0f);
    bottomInvader.position = (Vector2){ 540.0f, 915.0f };
    bottomInvader.presentationSide = SIDE_TOP;
    pathfind_face_goal(&bottomInvader, &bf, (Vector2){ 640.0f, 915.0f });
    assert(bottomInvader.anim.dir == DIR_SIDE);
    assert(bottomInvader.anim.flipH == false);
    assert(approx_eq(bottomInvader.spriteRotationDegrees, 180.0f, 0.001f));
    pathfind_face_goal(&bottomInvader, &bf, (Vector2){ 440.0f, 915.0f });
    assert(bottomInvader.anim.dir == DIR_SIDE);
    assert(bottomInvader.anim.flipH == true);
    assert(approx_eq(bottomInvader.spriteRotationDegrees, 180.0f, 0.001f));

    Entity topInvader = make_test_entity(1, 4, 0.0f);
    topInvader.ownerID = 1;
    topInvader.presentationSide = SIDE_BOTTOM;
    topInvader.position = (Vector2){ 540.0f, 1005.0f };
    pathfind_face_goal(&topInvader, &bf, (Vector2){ 640.0f, 1005.0f });
    assert(topInvader.anim.dir == DIR_SIDE);
    assert(topInvader.anim.flipH == true);
    assert(approx_eq(topInvader.spriteRotationDegrees, 0.0f, 0.001f));
    pathfind_face_goal(&topInvader, &bf, (Vector2){ 440.0f, 1005.0f });
    assert(topInvader.anim.dir == DIR_SIDE);
    assert(topInvader.anim.flipH == false);
    assert(approx_eq(topInvader.spriteRotationDegrees, 0.0f, 0.001f));
}

